// [UI CAPSULE] LIBRA_UI Namespace
// ══════════════════════════════════════════════════════════════
const LIBRA_UI = Object.freeze({
    GUI: LMAI_GUI,
    Dashboard: LIBRAActivityDashboard,
    _activeListeners: new WeakMap(),
    registerListener(element, event, handler, options = false) {
        if (!element) return;
        element.addEventListener(event, handler, options);
        let listeners = this._activeListeners.get(element);
        if (!listeners) {
            listeners = [];
            this._activeListeners.set(element, listeners);
        }
        listeners.push({ event, handler, options });
    },
    cleanupListener(element) {
        if (!element) return;
        const listeners = this._activeListeners.get(element);
        if (listeners) {
            listeners.forEach(({ event, handler, options }) => {
                element.removeEventListener(event, handler, options);
            });
            this._activeListeners.delete(element);
        }
    },
    cleanup() {
        if (typeof unbindUiInteractionGuards === 'function') unbindUiInteractionGuards();
    }
});

